import pytest

from your_module import zip_dicts  # Replace 'your_module' with the actual module name


def test_happy_path_multiple_dicts_with_overlapping_keys():
    """Test the happy path with multiple dictionaries having overlapping and unique keys."""
    d1 = {'a': 1, 'b': 2}
    d2 = {'b': 3, 'c': 4}
    result = zip_dicts(d1, d2)
    expected = {'a': [1, None], 'b': [2, 3], 'c': [None, 4]}
    assert result == expected


def test_happy_path_all_unique_keys():
    """Test multiple dictionaries with completely unique keys."""
    d1 = {'x': 10}
    d2 = {'y': 20}
    d3 = {'z': 30}
    result = zip_dicts(d1, d2, d3)
    expected = {'x': [10, None, None], 'y': [None, 20, None], 'z': [None, None, 30]}
    assert result == expected


def test_happy_path_dicts_with_none_values():
    """Test dictionaries containing None values."""
    d1 = {'a': None, 'b': 2}
    d2 = {'b': None, 'c': 4}
    result = zip_dicts(d1, d2)
    expected = {'a': [None, None], 'b': [2, None], 'c': [None, 4]}
    assert result == expected


def test_single_dictionary():
    """Test with exactly one dictionary."""
    d1 = {'a': 1, 'b': 2}
    result = zip_dicts(d1)
    expected = {'a': [1], 'b': [2]}
    assert result == expected


def test_no_dictionaries():
    """Test with zero dictionaries (empty *args)."""
    result = zip_dicts()
    assert result == {}


